export const DICT = { en, zh, es, vi };

const DEFAULT_LANG = "zh";
const STORAGE_KEY = "gomall_lang";

const I18nContext = createContext({
  lang: DEFAULT_LANG,
  setLang: () => {},
  t: (k) => k,
});

export function I18nProvider({ children }) {
  const [lang, setLangState] = useState(DEFAULT_LANG);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) setLangState(saved);
    } catch (err) {
      console.error("[I18nProvider] Failed to read language from localStorage:", err);
    }
  }, []);

  const setLang = (code) => {
    try {
      localStorage.setItem(STORAGE_KEY, code);
    } catch (err) {
      console.error("[I18nProvider] Failed to write language to localStorage:", err);
    }
    setLangState(code);
  };

  const t = (key, params) => {
    let str = DICT[lang]?.[key] ?? DICT.en[key] ?? key;
    if (params) Object.entries(params).forEach(([k, v]) => { str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), v); });
    return str;
  };

  return (
    <I18nContext.Provider value={{ lang, setLang, t }}>
      {children}
    </I18nContext.Provider>
  );
}

export function useI18n() {
  return useContext(I18nContext);
}
